-- PostgreSQL version of category (doctor-per-poli schedule assignments)
DROP TABLE IF EXISTS category CASCADE;
CREATE TABLE category (
  id SERIAL PRIMARY KEY,
  name VARCHAR(255) DEFAULT NULL,
  subname VARCHAR(255) DEFAULT NULL,
  namadokter VARCHAR(255) DEFAULT NULL,
  slug VARCHAR(255) DEFAULT NULL,
  order_sort INTEGER NOT NULL DEFAULT 0,
  kodereff VARCHAR(255) DEFAULT NULL,
  jadwal TEXT DEFAULT NULL,
  senin VARCHAR(255) DEFAULT NULL,
  selasa VARCHAR(255) DEFAULT NULL,
  rabu VARCHAR(255) DEFAULT NULL,
  kamis VARCHAR(255) DEFAULT NULL,
  jumat VARCHAR(255) DEFAULT NULL,
  sabtu VARCHAR(255) DEFAULT NULL,
  minggu VARCHAR(255) DEFAULT NULL,
  eksekutif INTEGER NOT NULL DEFAULT 0,
  jkn INTEGER NOT NULL DEFAULT 1,
  "KodeDokter" VARCHAR(255) DEFAULT NULL,
  "IdDokter" INTEGER NOT NULL DEFAULT 0,
  "IdPoli" INTEGER NOT NULL DEFAULT 0,
  app INTEGER NOT NULL DEFAULT 0,
  "KuotaJKN" INTEGER NOT NULL DEFAULT 30,
  "KuotaNonJKN" INTEGER NOT NULL DEFAULT 30,
  options TEXT NOT NULL DEFAULT '',
  voice_call VARCHAR(255) NOT NULL DEFAULT ''
);

